mapper.select:
SELECT cps.* FROM store_coach cps WHERE cps.status=1
AND (cps.storeId is null or cps.storeId = '' or find_in_set(#{storeId}, cps.storeId))
AND cps.grade=#{grade}
ORDER BY cps.level DESC
limit #{offset}, #{limit}

SELECT count(*) FROM store_coach cps WHERE cps.status=1
AND (cps.storeId is null or cps.storeId = '' or find_in_set(#{storeId}, cps.storeId))
AND cps.grade=#{grade}
ORDER BY cps.level DESC
limit #{offset}, #{limit}
